-- Data Skill Map - Question Bank Reset v1
-- Este script define a base v1 como conjunto ativo oficial.
-- Qualquer pergunta fora de `diagnostico_v1_%` e `desafio_v1_%` será desativada.
-- Não apaga histórico, não usa DELETE e não recria tabelas.

begin;

-- Auditoria de duplicidade (ignora question_key nulo)
select question_key, count(*) as total
from public.question_bank
where question_key is not null
group by question_key
having count(*) > 1;

do $$
begin
  if exists (
    select 1
    from public.question_bank
    where question_key is not null
    group by question_key
    having count(*) > 1
  ) then
    raise exception 'Existem question_key duplicadas em public.question_bank. Corrija antes de continuar.';
  end if;
end $$;

create unique index if not exists question_bank_question_key_uidx
on public.question_bank (question_key);

update public.question_bank
set is_active = false,
    updated_at = now()
where coalesce(question_key, '') not like 'diagnostico_v1_%'
  and coalesce(question_key, '') not like 'desafio_v1_%';

insert into public.question_bank (
  question_key,
  mode,
  area,
  category,
  level,
  concept,
  question,
  code,
  context,
  options,
  correct_index,
  explanation,
  points,
  is_active,
  display_order,
  source,
  difficulty_score,
  question_type,
  tags,
  estimated_time_seconds
)
values
  ('diagnostico_v1_001', 'diagnostico', 'SQL', 'SQL', 'Básico', 'Filtro de período', 'Você recebeu um pedido para mostrar apenas as vendas dos últimos 30 dias. Qual abordagem SQL atende melhor ao pedido?', '', 'Tabela vendas possui data_venda e valor.', '["Aplicar WHERE data_venda >= data atual menos 30 dias","Ordenar por data_venda descendente","Usar GROUP BY data_venda","Usar DISTINCT em data_venda"]'::jsonb, 0, 'Para limitar linhas por período, o filtro deve estar no WHERE.', null, true, 1, 'question_bank_reset_v1', 2, 'cenario', array['sql','where','filtro_data'], 60),
