-- Validações pós-execução
select mode, count(*) as total
from public.question_bank
where is_active = true
group by mode
order by mode;

select mode, level, count(*) as total
from public.question_bank
where is_active = true
group by mode, level
order by mode, level;

select mode, area, count(*) as total
from public.question_bank
where is_active = true
group by mode, area
order by mode, area;

select mode, is_active, count(*) as total
from public.question_bank
group by mode, is_active
order by mode, is_active desc;

